const lead = $input.first().json;
const followupCount = lead.followup_count || 0;

let emailSubject = '';
let emailBody = '';

if (followupCount === 0) {
  emailSubject = `Following up: ${lead.company} / ${lead.name}`;
  emailBody = `Hi ${lead.name},\n\nJust wanted to follow up on my previous email. I'd love to chat about how we can help ${lead.company} with our AI solutions.\n\nAre you available for a quick 15-minute call next week?\n\nBest regards,\nSales Team`;
} else if (followupCount === 1) {
  emailSubject = `Re: ${lead.company} - AI Solutions`;
  emailBody = `Hi ${lead.name},\n\nI wanted to share a case study of how we helped a similar company in your industry increase their lead conversion by 40%.\n\nWould you be open to seeing how this could apply to ${lead.company}?\n\nBest,\nSales Team`;
} else {
  emailSubject = `Final attempt: ${lead.company}`;
  emailBody = `Hi ${lead.name},\n\nThis is my last attempt to reach you. We're running a special offer for companies like ${lead.company} this month.\n\nIf you're interested, let me know. If not, I'll stop reaching out.\n\nThanks,\nSales Team`;
}

return {
  lead_id: lead.id,
  email: lead.email,
  name: lead.name,
  company: lead.company,
  followup_count: followupCount,
  email_subject: emailSubject,
  email_body: emailBody
};
